import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"左手的小短弓","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/远程武器/1.D级/左手的小短弓.md","filePath":"4.资源分区/7.物品与装备/2.武器/远程武器/1.D级/左手的小短弓.md"}'),d={name:"4.资源分区/7.物品与装备/2.武器/远程武器/1.D级/左手的小短弓.md"};function _(l,a,i,p,c,h){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"左手的小短弓",tabindex:"-1"},[s("左手的小短弓 "),e("a",{class:"header-anchor",href:"#左手的小短弓","aria-label":'Permalink to "左手的小短弓"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风027")])])],-1),o('<h1 id="左手的小短弓-1" tabindex="-1">左手的小短弓 <a class="header-anchor" href="#左手的小短弓-1" aria-label="Permalink to &quot;左手的小短弓&quot;">​</a></h1><p>左手的小短弓<br> 魔幻本质<br> D+500<br> 描述：于无数个被卡在数据与庭院之间的左手上的时空，这把弓凝望过太多小骑士的落幕，聆听过无数小骑士的悲鸣与踹哈的狂笑，于是，一切的怨念、执念、仇恨与渴望凝聚于此。<br> 特性：这是一把仅有体积2、武器伤害6L的小巧短弓，材质是普通的去皮橡木，不普通的则是，仅在右手正常装备弓箭类武器时，可以自由动作将这把短弓卡在左手，这依然满足弓箭的双手要求，不止能够正常射击，右手的弓还会因此超快速持续不断地射箭，这视为具有【无限子弹】特性并将弓箭的速射等级提升至【连射】，右手就像是一只无形的手在疯狂拉弓一般抽搐，发射出无数的箭矢淹没敌人，但你会因此无法进行瞄准。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',4)])])}const m=r(d,[["render",_]]);export{f as __pageData,m as default};
